mapper.select:
SELECT STPLT_SEQ,STPLT_CTG_CD,STPLT_CTG_NM,STPLT_TITLE,SHOW_YN,STPLT_SBST,CRET_ID,AMD_ID,CRET_DT,AMD_DT,STPLT_HIT,NEXT_SEQ,NEXT_TITLE,NEXT_CRET_DT,PRE_SEQ,PRE_TITLE,PRE_CRET_DT FROM ( SELECT STPLT_SEQ, STPLT_CTG_CD, (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = 'TERMS' AND DTL_CD = STPLT_CTG_CD) AS STPLT_CTG_NM, STPLT_TITLE, SHOW_YN, STPLT_SBST, CRET_ID, AMD_ID, TO_CHAR(CRET_DT, 'YYYY.MM.DD') AS CRET_DT, TO_CHAR(AMD_DT, 'YYYY.MM.DD') AS AMD_DT, STPLT_HIT, LEAD(STPLT_SEQ,1) over (order by STPLT_SEQ) NEXT_SEQ, LEAD(STPLT_TITLE,1,'다음글이 없습니다.') OVER (ORDER BY STPLT_SEQ) NEXT_TITLE, TO_CHAR(LEAD(CRET_DT,1) OVER (ORDER BY STPLT_SEQ), 'YYYY.MM.DD') NEXT_CRET_DT, LAG(STPLT_SEQ,1) over (order by STPLT_SEQ) PRE_SEQ, LAG(STPLT_TITLE,1,'이전글이 없습니다.') OVER (ORDER BY STPLT_SEQ) PRE_TITLE, TO_CHAR(LAG(CRET_DT,1) OVER (ORDER BY STPLT_SEQ), 'YYYY.MM.DD') PRE_CRET_DT FROM NMCP_STPLT_BAS WHERE 1=1 AND STPLT_CTG_CD = '06' AND SITE_CODE = #{siteCode} AND SHOW_YN = 'Y' ) WHERE
STPLT_SEQ = #{stpltSeq}
STPLT_SEQ = (SELECT MAX(STPLT_SEQ) FROM NMCP_STPLT_BAS WHERE STPLT_CTG_CD = '06' AND SHOW_YN = 'Y' AND SITE_CODE = #{siteCode})

SELECT ROW_NUMBER() OVER (ORDER BY STPLT_SEQ ASC) AS ROW_NUM, A.STPLT_SEQ, A.STPLT_CTG_CD, (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = 'TERMS' AND DTL_CD = STPLT_CTG_CD) AS STPLT_CTG_NM, A.STPLT_TITLE, A.SHOW_YN, A.CRET_ID, A.AMD_ID, TO_CHAR(A.CRET_DT, 'YYYY.MM.DD') AS CRET_DT, TO_CHAR(A.AMD_DT, 'YYYY.MM.DD') AS AMD_DT, A.STPLT_HIT, B.STPLT_BAS_SEQ, B.FILE_NM, B.REAL_FILE_NM, B.FILE_TYPE, B.FILE_PATH_NM, B.ATT_SEQ FROM NMCP_STPLT_BAS A, NMCP_STPLT_DTL B WHERE A.STPLT_SEQ = B.STPLT_BAS_SEQ AND A.STPLT_CTG_CD NOT IN('06','05') AND SHOW_YN = 'Y'
AND A.STPLT_CTG_CD = #{stpltCtgCd}
ORDER BY A.STPLT_SEQ DESC

SELECT STPLT_SEQ , STPLT_CTG_CD , STPLT_CTG_NM , STPLT_TITLE , SHOW_YN , STPLT_SBST , CRET_ID , AMD_ID , CRET_DT , AMD_DT , STPLT_HIT , NEXT_SEQ , NEXT_TITLE , NEXT_CRET_DT , PRE_SEQ , PRE_TITLE , PRE_CRET_DT , STPLT_BAS_SEQ , FILE_NM , REAL_FILE_NM , FILE_TYPE , FILE_PATH_NM , ATT_SEQ FROM ( SELECT A.STPLT_SEQ, A.STPLT_CTG_CD, (SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID = 'TERMS' AND DTL_CD = STPLT_CTG_CD) AS STPLT_CTG_NM, A.STPLT_TITLE, A.SHOW_YN, A.STPLT_SBST, A.CRET_ID, A.AMD_ID, TO_CHAR(A.CRET_DT, 'YYYY.MM.DD') AS CRET_DT, TO_CHAR(A.AMD_DT, 'YYYY.MM.DD') AS AMD_DT, A.STPLT_HIT, LEAD(A.STPLT_SEQ,1) over (order by A.STPLT_SEQ) NEXT_SEQ, LEAD(A.STPLT_TITLE,1,'다음글이 없습니다.') OVER (ORDER BY A.STPLT_SEQ) NEXT_TITLE, TO_CHAR(LEAD(A.CRET_DT,1) OVER (ORDER BY A.STPLT_SEQ), 'YYYY.MM.DD') NEXT_CRET_DT, LAG(A.STPLT_SEQ,1) over (order by A.STPLT_SEQ) PRE_SEQ, LAG(A.STPLT_TITLE,1,'이전글이 없습니다.') OVER (ORDER BY A.STPLT_SEQ) PRE_TITLE, TO_CHAR(LAG(A.CRET_DT,1) OVER (ORDER BY A.STPLT_SEQ), 'YYYY.MM.DD') PRE_CRET_DT, B.STPLT_BAS_SEQ, B.FILE_NM, B.REAL_FILE_NM, B.FILE_TYPE, B.FILE_PATH_NM, B.ATT_SEQ FROM NMCP_STPLT_BAS A, NMCP_STPLT_DTL B WHERE 1=1 AND A.STPLT_SEQ = B.STPLT_BAS_SEQ AND A.STPLT_CTG_CD NOT IN('06','05')
AND A.STPLT_CTG_CD = #{stpltCtgCd}
AND A.SHOW_YN = 'Y' ) WHERE STPLT_SEQ = #{stpltSeq}

mapper.update:
UPDATE	NMCP_STPLT_BAS
SET
		STPLT_HIT = NVL(STPLT_HIT, 0) + 1
WHERE	STPLT_SEQ = #{stpltSeq}

AND 	CRET_ID != #{sessionId}
